 1→import {
 2→  createContext,
 3→  useContext,
 4→  useState,
 5→  useCallback,
 6→  type ReactNode,
 7→} from 'react';
 8→
 9→type ToastType = 'success' | 'error' | 'info';
10→
11→interface Toast {
12→  id: number;
13→  message: string;
14→  type: ToastType;
15→}
16→
17→interface ToastContextValue {
18→  toast: (message: string, type?: ToastType) => void;
19→}
20→
21→const ToastContext = createContext<ToastContextValue | null>(null);
22→
23→let nextId = 0;
24→
25→export function ToastProvider({ children }: { children: ReactNode }) {
26→  const [toasts, setToasts] = useState<Toast[]>([]);
27→
28→  const toast = useCallback((message: string, type: ToastType = 'info') => {
29→    const id = nextId++;
30→    setToasts((prev) => [...prev, { id, message, type }]);
31→    setTimeout(() => {
32→      setToasts((prev) => prev.filter((t) => t.id !== id));
33→    }, 4000);
34→  }, []);
35→
36→  const dismiss = useCallback((id: number) => {
37→    setToasts((prev) => prev.filter((t) => t.id !== id));
38→  }, []);
39→
40→  return (
41→    <ToastContext.Provider value={{ toast }}>
42→      {children}
43→      <div className="fixed bottom-4 right-4 z-50 flex flex-col gap-2">
44→        {toasts.map((t) => (
45→          <div
46→            key={t.id}
47→            role="alert"
48→            className={`flex items-center gap-3 rounded-lg px-4 py-3 text-sm font-medium text-white shadow-lg transition-all ${
49→              t.type === 'success'
50→                ? 'bg-green-600'
51→                : t.type === 'error'
52→                  ? 'bg-red-600'
53→                  : 'bg-[var(--color-primary)]'
54→            }`}
55→          >
56→            <span className="flex-1">{t.message}</span>
57→            <button
58→              onClick={() => dismiss(t.id)}
59→              className="text-white/80 hover:text-white"
60→              aria-label="Fermer"
61→            >
62→              &times;
63→            </button>
64→          </div>
65→        ))}
66→      </div>
67→    </ToastContext.Provider>
68→  );
69→}
70→
71→export function useToast(): ToastContextValue {
72→  const ctx = useContext(ToastContext);
73→  if (!ctx) {
74→    throw new Error('useToast doit etre utilise dans un ToastProvider');
75→  }
76→  return ctx;
77→}
