 1→import { useEffect, useRef, type ReactNode } from 'react';
 2→
 3→interface ModalProps {
 4→  isOpen: boolean;
 5→  onClose: () => void;
 6→  title: string;
 7→  children: ReactNode;
 8→  size?: 'sm' | 'md' | 'lg';
 9→}
10→
11→const sizeClasses = {
12→  sm: 'max-w-sm',
13→  md: 'max-w-lg',
14→  lg: 'max-w-2xl',
15→};
16→
17→export function Modal({ isOpen, onClose, title, children, size = 'md' }: ModalProps) {
18→  const overlayRef = useRef<HTMLDivElement>(null);
19→
20→  useEffect(() => {
21→    if (!isOpen) return;
22→    const handleEscape = (e: KeyboardEvent) => {
23→      if (e.key === 'Escape') onClose();
24→    };
25→    document.addEventListener('keydown', handleEscape);
26→    return () => document.removeEventListener('keydown', handleEscape);
27→  }, [isOpen, onClose]);
28→
29→  if (!isOpen) return null;
30→
31→  return (
32→    <div
33→      ref={overlayRef}
34→      className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 p-4"
35→      onClick={(e) => {
36→        if (e.target === overlayRef.current) onClose();
37→      }}
38→    >
39→      <div
40→        className={`w-full ${sizeClasses[size]} animate-in fade-in rounded-xl bg-[var(--color-surface)] p-6 shadow-xl`}
41→      >
42→        <div className="mb-4 flex items-center justify-between">
43→          <h2 className="text-lg font-semibold text-[var(--color-text)]">
44→            {title}
45→          </h2>
46→          <button
47→            onClick={onClose}
48→            className="flex h-8 w-8 items-center justify-center rounded-lg text-[var(--color-text-muted)] transition-colors hover:bg-slate-100"
49→          >
50→            ✕
51→          </button>
52→        </div>
53→        {children}
54→      </div>
55→    </div>
56→  );
57→}
