 43→export function PushProvider({ children }: { children: ReactNode }) {
 44→  const { user, isAuthenticated } = useAuth();
 45→  const [isSupported] = useState(() => 'Notification' in window && 'serviceWorker' in navigator);
 46→  const [isPermissionGranted, setIsPermissionGranted] = useState(false);
 47→  const [isSubscribed, setIsSubscribed] = useState(false);
 48→  const [playerId, setPlayerId] = useState<string | null>(null);
 49→  const [loading, setLoading] = useState(true);
 50→
 51→  // Initialize OneSignal when user is authenticated
 52→  useEffect(() => {
 53→    if (!isAuthenticated || !user || !isSupported) {
 54→      setLoading(false);
 55→      return;
 56→    }
 57→
 58→    async function setup() {
 59→      try {
 60→        await initOneSignal();
 61→
 62→        if (!isOneSignalReady()) {
 63→          setLoading(false);
 64→          return;
 65→        }
 66→
 67→        await setExternalUserId(user!.id);
 68→
 69→        const permission = OneSignal.Notifications.permission;
 70→        setIsPermissionGranted(permission);
 71→
 72→        if (permission) {
 73→          const pid = await getPlayerId();
 74→          setPlayerId(pid);
 75→
 76→          if (pid) {
 77→            await registerPlayerInDb(user!.id, pid);
 78→            setIsSubscribed(true);
 79→          }
 80→        }
 81→      } catch (err) {
 82→        console.warn('OneSignal init error:', err);
 83→      }
 84→      setLoading(false);
 85→    }
 86→
 87→    setup();
 88→  }, [isAuthenticated, user?.id, isSupported]);
 89→
 90→  // Listen for permission changes
 91→  useEffect(() => {
 92→    if (!isOneSignalReady()) return;
 93→
 94→    const handlePermissionChange = (granted: boolean) => {
 95→      setIsPermissionGranted(granted);
 96→      if (!granted && user) {
 97→        deactivateSubscription(user.id);
 98→        setIsSubscribed(false);
 99→        setPlayerId(null);
100→      }
101→    };
102→
103→    OneSignal.Notifications.addEventListener('permissionChange', handlePermissionChange);
104→    return () => {
105→      OneSignal.Notifications.removeEventListener('permissionChange', handlePermissionChange);
106→    };
107→  }, [user?.id]);
108→
109→  const requestPermission = useCallback(async (): Promise<boolean> => {
110→    if (!isOneSignalReady()) return false;
111→
112→    const granted = await promptForPush();
113→    setIsPermissionGranted(granted);
114→
115→    if (granted && user) {
116→      const pid = await getPlayerId();
117→      setPlayerId(pid);
118→      if (pid) {
119→        await registerPlayerInDb(user.id, pid);
120→        setIsSubscribed(true);
121→      }
122→    }
